import { Vex } from 'vex-sdk';
import { AgentRuntime } from '@azure/ai-projects';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });
const FEDRAMP_POLICY = {
  blockCUI: true,
  validateTools: ['file_search', 'bing_search'],
  requireFreshness: '7d'
};

// Middleware for Azure AI Agent tool calls
export const govToolGuard = async (toolCall: any): Promise<any> => {
  const validation = await vex.validateTool({
    toolName: toolCall.name,
    parameters: toolCall.args,
    policy: FEDRAMP_POLICY,
    metadata: { classification: 'CUI', agency: 'HHS' }
  });

  if (!validation.approved) {
    throw new Error(`FedRAMP Violation: ${validation.violations.join(', ')}`);
  }

  // Execute only approved tools
  const result = await AgentRuntime.executeTool(toolCall);

  // Validate tool output
  const outputValidation = await vex.validate({
    input: result.content,
    context: 'tool_output',
    policy_set: 'nist-800-53'
  });

  return outputValidation.approved ? result : {
    content: '[REDACTED - Policy Violation]',
    metadata: { vex_blocked: true }
  };
};
